import React from 'react';

const Hero = () => {
  return (
    <section id="home" className="flex flex-col-reverse md:flex-row items-center justify-between min-h-screen p-6 md:p-20">
      <div className="md:w-1/2 text-center md:text-left">
        <h1 className="text-5xl font-bold mb-6">Hi, I'm Sindhuja</h1>
        <p className="text-gray-600 text-lg mb-6">
          I'm a web developer creating modern and responsive websites.
        </p>
        <button className="bg-black text-white px-8 py-4 rounded hover:bg-red-600 transition">
          Contact Me
        </button>
      </div>
      <div className="md:w-1/2 mb-8 md:mb-0">
        <img src="/profile.png" alt="Profile" className="w-full h-auto rounded-full"/>
      </div>
    </section>
  );
};

export default Hero;
